window.BIBLE["SongofSolomon"] = {"1":{"chapter":"1","title":"THE BELOVED'S SONG BEGINS","verses":{"1":{"text":"The song of songs, which is Solomon’s.","ref":"Song of Solomon 1:1","synthesized":"This is Solomon’s Song of Songs.","sources":{"KJV":{"text":"The song of songs, which is Solomon’s."},"BSB":{"text":"This is Solomon’s Song of Songs."}},"definableWords":[],"peopleInVerse":["Solomon"]},"2":{"text":"Let him kiss me with the kisses of his mouth: for thy love is better than wine.","ref":"Song of Solomon 1:2","synthesized":"Let him kiss me with the kisses of his mouth! For your love is more delightful than wine.","sources":{"KJV":{"text":"Let him kiss me with the kisses of his mouth: for thy love is better than wine."},"BSB":{"text":"Let him kiss me with the kisses of his mouth! For your love is more delightful than wine."}},"definableWords":["love"],"peopleInVerse":[]},"3":{"text":"Because of the savour of thy good ointments thy name is as ointment poured forth, therefore do the virgins love thee.","ref":"Song of Solomon 1:3","synthesized":"The fragrance of your perfume is pleasing; your name is like perfume poured out. No wonder the maidens adore you.","sources":{"KJV":{"text":"Because of the savour of thy good ointments thy name is as ointment poured forth, therefore do the virgins love thee."},"BSB":{"text":"The fragrance of your perfume is pleasing; your name is like perfume poured out. No wonder the maidens adore you."}},"definableWords":["name"],"peopleInVerse":[]},"4":{"text":"Draw me, we will run after thee: the king hath brought me into his chambers: we will be glad and rejoice in thee, we will remember thy love more than wine: the upright love thee.","ref":"Song of Solomon 1:4","synthesized":"Take me away with you—let us hurry! May the king bring me to his chambers.    We will rejoice and delight in you; we will praise your love more than wine.    It is only right that they adore you.","sources":{"KJV":{"text":"Draw me, we will run after thee: the king hath brought me into his chambers: we will be glad and rejoice in thee, we will remember thy love more than wine: the upright love thee."},"BSB":{"text":"Take me away with you—let us hurry! May the king bring me to his chambers.    We will rejoice and delight in you; we will praise your love more than wine.    It is only right that they adore you."}},"definableWords":["king","praise","love"],"peopleInVerse":[]},"5":{"text":"I am black, but comely, O ye daughters of Jerusalem, as the tents of Kedar, as the curtains of Solomon.","ref":"Song of Solomon 1:5","synthesized":"I am dark, yet lovely, O daughters of Jerusalem, like the tents of Kedar, like the curtains of Solomon.","sources":{"KJV":{"text":"I am black, but comely, O ye daughters of Jerusalem, as the tents of Kedar, as the curtains of Solomon."},"BSB":{"text":"I am dark, yet lovely, O daughters of Jerusalem, like the tents of Kedar, like the curtains of Solomon."}},"definableWords":["daughters","Jerusalem"],"peopleInVerse":["Solomon"]},"6":{"text":"Look not upon me, because I am black, because the sun hath looked upon me: my mother’s children were angry with me; they made me the keeper of the vineyards; but mine own vineyard have I not kept.","ref":"Song of Solomon 1:6","synthesized":"Do not stare because I am dark, for the sun has gazed upon me. My mother’s sons were angry with me; they made me a keeper of the vineyards, but my own vineyard I have neglected.","sources":{"KJV":{"text":"Look not upon me, because I am black, because the sun hath looked upon me: my mother’s children were angry with me; they made me the keeper of the vineyards; but mine own vineyard have I not kept."},"BSB":{"text":"Do not stare because I am dark, for the sun has gazed upon me. My mother’s sons were angry with me; they made me a keeper of the vineyards, but my own vineyard I have neglected."}},"definableWords":["mother","sons","made"],"peopleInVerse":[]},"7":{"text":"Tell me, O thou whom my soul loveth, where thou feedest, where thou makest thy flock to rest at noon: for why should I be as one that turneth aside by the flocks of thy companions?","ref":"Song of Solomon 1:7","synthesized":"Tell me, O one I love, where do you pasture your sheep? Where do you rest them at midday? Why should I be like a veiled woman beside the flocks of your companions?","sources":{"KJV":{"text":"Tell me, O thou whom my soul loveth, where thou feedest, where thou makest thy flock to rest at noon: for why should I be as one that turneth aside by the flocks of thy companions?"},"BSB":{"text":"Tell me, O one I love, where do you pasture your sheep? Where do you rest them at midday? Why should I be like a veiled woman beside the flocks of your companions?"}},"definableWords":["one","love","rest","woman"],"peopleInVerse":[]},"8":{"text":"If thou know not, O thou fairest among women, go thy way forth by the footsteps of the flock, and feed thy kids beside the shepherds’ tents.","ref":"Song of Solomon 1:8","synthesized":"If you do not know, O fairest of women, follow the tracks of the flock, and graze your young goats near the tents of the shepherds.","sources":{"KJV":{"text":"If thou know not, O thou fairest among women, go thy way forth by the footsteps of the flock, and feed thy kids beside the shepherds’ tents."},"BSB":{"text":"If you do not know, O fairest of women, follow the tracks of the flock, and graze your young goats near the tents of the shepherds."}},"definableWords":["women"],"peopleInVerse":[]},"9":{"text":"I have compared thee, O my love, to a company of horses in Pharaoh’s chariots.","ref":"Song of Solomon 1:9","synthesized":"I compare you, my darling, to a mare among Pharaoh’s chariots.","sources":{"KJV":{"text":"I have compared thee, O my love, to a company of horses in Pharaoh’s chariots."},"BSB":{"text":"I compare you, my darling, to a mare among Pharaoh’s chariots."}},"definableWords":["Pharaoh"],"peopleInVerse":["Pharaoh"]},"10":{"text":"Thy cheeks are comely with rows of jewels, thy neck with chains of gold.","ref":"Song of Solomon 1:10","synthesized":"Your cheeks are beautiful with ornaments, your neck with strings of jewels.","sources":{"KJV":{"text":"Thy cheeks are comely with rows of jewels, thy neck with chains of gold."},"BSB":{"text":"Your cheeks are beautiful with ornaments, your neck with strings of jewels."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"We will make thee borders of gold with studs of silver.","ref":"Song of Solomon 1:11","synthesized":"We will make you ornaments of gold, studded with beads of silver.","sources":{"KJV":{"text":"We will make thee borders of gold with studs of silver."},"BSB":{"text":"We will make you ornaments of gold, studded with beads of silver."}},"definableWords":["make"],"peopleInVerse":[]},"12":{"text":"While the king sitteth at his table, my spikenard sendeth forth the smell thereof.","ref":"Song of Solomon 1:12","synthesized":"While the king was at his table, my perfume spread its fragrance.","sources":{"KJV":{"text":"While the king sitteth at his table, my spikenard sendeth forth the smell thereof."},"BSB":{"text":"While the king was at his table, my perfume spread its fragrance."}},"definableWords":["king"],"peopleInVerse":[]},"13":{"text":"A bundle of myrrh is my well-beloved unto me; he shall lie all night betwixt my breasts.","ref":"Song of Solomon 1:13","synthesized":"My beloved is to me a sachet of myrrh resting between my breasts.","sources":{"KJV":{"text":"A bundle of myrrh is my well-beloved unto me; he shall lie all night betwixt my breasts."},"BSB":{"text":"My beloved is to me a sachet of myrrh resting between my breasts."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"My beloved is unto me as a cluster of camphire in the vineyards of Engedi.","ref":"Song of Solomon 1:14","synthesized":"My beloved is to me a cluster of henna blossoms in the vineyards of En-gedi.","sources":{"KJV":{"text":"My beloved is unto me as a cluster of camphire in the vineyards of Engedi."},"BSB":{"text":"My beloved is to me a cluster of henna blossoms in the vineyards of En-gedi."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"Behold, thou art fair, my love; behold, thou art fair; thou hast doves’ eyes.","ref":"Song of Solomon 1:15","synthesized":"How beautiful you are, my darling! Oh, how very beautiful! Your eyes are like doves.","sources":{"KJV":{"text":"Behold, thou art fair, my love; behold, thou art fair; thou hast doves’ eyes."},"BSB":{"text":"How beautiful you are, my darling! Oh, how very beautiful! Your eyes are like doves."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"Behold, thou art fair, my beloved, yea, pleasant: also our bed is green.","ref":"Song of Solomon 1:16","synthesized":"How handsome you are, my beloved! Oh, how delightful! The soft grass is our bed.","sources":{"KJV":{"text":"Behold, thou art fair, my beloved, yea, pleasant: also our bed is green."},"BSB":{"text":"How handsome you are, my beloved! Oh, how delightful! The soft grass is our bed."}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"The beams of our house are cedar, and our rafters of fir.","ref":"Song of Solomon 1:17","synthesized":"The beams of our house are cedars; our rafters are fragrant firs.","sources":{"KJV":{"text":"The beams of our house are cedar, and our rafters of fir."},"BSB":{"text":"The beams of our house are cedars; our rafters are fragrant firs."}},"definableWords":["house"],"peopleInVerse":[]}}},"2":{"chapter":"2","title":"I AM MY BELOVED'S","verses":{"1":{"text":"I am the rose of Sharon, and the lily of the valleys.","ref":"Song of Solomon 2:1","synthesized":"I am a rose of Sharon, a lily of the valley.","sources":{"KJV":{"text":"I am the rose of Sharon, and the lily of the valleys."},"BSB":{"text":"I am a rose of Sharon, a lily of the valley."}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"As the lily among thorns, so is my love among the daughters.","ref":"Song of Solomon 2:2","synthesized":"Like a lily among the thorns is my darling among the maidens.","sources":{"KJV":{"text":"As the lily among thorns, so is my love among the daughters."},"BSB":{"text":"Like a lily among the thorns is my darling among the maidens."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"As the apple tree among the trees of the wood, so is my beloved among the sons. I sat down under his shadow with great delight, and his fruit was sweet to my taste.","ref":"Song of Solomon 2:3","synthesized":"Like an apple tree among the trees of the forest is my beloved among the young men. I delight to sit in his shade, and his fruit is sweet to my taste.","sources":{"KJV":{"text":"As the apple tree among the trees of the wood, so is my beloved among the sons. I sat down under his shadow with great delight, and his fruit was sweet to my taste."},"BSB":{"text":"Like an apple tree among the trees of the forest is my beloved among the young men. I delight to sit in his shade, and his fruit is sweet to my taste."}},"definableWords":["tree","trees","men"],"peopleInVerse":[]},"4":{"text":"He brought me to the banqueting house, and his banner over me was love.","ref":"Song of Solomon 2:4","synthesized":"He has brought me to the house of wine, and his banner over me is love.","sources":{"KJV":{"text":"He brought me to the banqueting house, and his banner over me was love."},"BSB":{"text":"He has brought me to the house of wine, and his banner over me is love."}},"definableWords":["house","love"],"peopleInVerse":[]},"5":{"text":"Stay me with flagons, comfort me with apples: for I am sick of love.","ref":"Song of Solomon 2:5","synthesized":"Sustain me with raisins; refresh me with apples, for I am faint with love.","sources":{"KJV":{"text":"Stay me with flagons, comfort me with apples: for I am sick of love."},"BSB":{"text":"Sustain me with raisins; refresh me with apples, for I am faint with love."}},"definableWords":["love"],"peopleInVerse":[]},"6":{"text":"His left hand is under my head, and his right hand doth embrace me.","ref":"Song of Solomon 2:6","synthesized":"His left hand is under my head, and his right arm embraces me.","sources":{"KJV":{"text":"His left hand is under my head, and his right hand doth embrace me."},"BSB":{"text":"His left hand is under my head, and his right arm embraces me."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"I charge you, O ye daughters of Jerusalem, by the roes, and by the hinds of the field, that ye stir not up, nor awake my love, till he please.","ref":"Song of Solomon 2:7","synthesized":"O daughters of Jerusalem, I adjure you by the gazelles and does of the field: Do not arouse or awaken love until the time is right.","sources":{"KJV":{"text":"I charge you, O ye daughters of Jerusalem, by the roes, and by the hinds of the field, that ye stir not up, nor awake my love, till he please."},"BSB":{"text":"O daughters of Jerusalem, I adjure you by the gazelles and does of the field: Do not arouse or awaken love until the time is right."}},"definableWords":["daughters","Jerusalem","field","or","love"],"peopleInVerse":[]},"8":{"text":"The voice of my beloved! behold, he cometh leaping upon the mountains, skipping upon the hills.","ref":"Song of Solomon 2:8","synthesized":"Listen! My beloved approaches. Look! Here he comes, leaping across the mountains, bounding over the hills.","sources":{"KJV":{"text":"The voice of my beloved! behold, he cometh leaping upon the mountains, skipping upon the hills."},"BSB":{"text":"Listen! My beloved approaches. Look! Here he comes, leaping across the mountains, bounding over the hills."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"My beloved is like a roe or a young hart: behold, he standeth behind our wall, he looketh forth at the windows, shewing himself through the lattice.","ref":"Song of Solomon 2:9","synthesized":"My beloved is like a gazelle or a young stag. Look, he stands behind our wall, gazing through the windows, peering through the lattice.","sources":{"KJV":{"text":"My beloved is like a roe or a young hart: behold, he standeth behind our wall, he looketh forth at the windows, shewing himself through the lattice."},"BSB":{"text":"My beloved is like a gazelle or a young stag. Look, he stands behind our wall, gazing through the windows, peering through the lattice."}},"definableWords":["or"],"peopleInVerse":[]},"10":{"text":"My beloved spake, and said unto me, Rise up, my love, my fair one, and come away.","ref":"Song of Solomon 2:10","synthesized":"My beloved calls to me, “Arise, my darling. Come away with me, my beautiful one.","sources":{"KJV":{"text":"My beloved spake, and said unto me, Rise up, my love, my fair one, and come away."},"BSB":{"text":"My beloved calls to me, “Arise, my darling. Come away with me, my beautiful one."}},"definableWords":["one"],"peopleInVerse":[]},"11":{"text":"For, lo, the winter is past, the rain is over and gone;","ref":"Song of Solomon 2:11","synthesized":"For now the winter is past; the rain is over and gone.","sources":{"KJV":{"text":"For, lo, the winter is past, the rain is over and gone;"},"BSB":{"text":"For now the winter is past; the rain is over and gone."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"The flowers appear on the earth; the time of the singing of birds is come, and the voice of the turtle is heard in our land;","ref":"Song of Solomon 2:12","synthesized":"The flowers have appeared in the countryside; the season of singing has come, and the cooing of turtledoves is heard in our land.","sources":{"KJV":{"text":"The flowers appear on the earth; the time of the singing of birds is come, and the voice of the turtle is heard in our land;"},"BSB":{"text":"The flowers have appeared in the countryside; the season of singing has come, and the cooing of turtledoves is heard in our land."}},"definableWords":["land"],"peopleInVerse":[]},"13":{"text":"The fig tree putteth forth her green figs, and the vines with the tender grape give a good smell. Arise, my love, my fair one, and come away.","ref":"Song of Solomon 2:13","synthesized":"The fig tree ripens its figs; the blossoming vines spread their fragrance. Arise, come away, my darling; come away with me, my beautiful one.”","sources":{"KJV":{"text":"The fig tree putteth forth her green figs, and the vines with the tender grape give a good smell. Arise, my love, my fair one, and come away."},"BSB":{"text":"The fig tree ripens its figs; the blossoming vines spread their fragrance. Arise, come away, my darling; come away with me, my beautiful one.”"}},"definableWords":["tree","one"],"peopleInVerse":[]},"14":{"text":"O my dove, that art in the clefts of the rock, in the secret places of the stairs, let me see thy countenance, let me hear thy voice; for sweet is thy voice, and thy countenance is comely.","ref":"Song of Solomon 2:14","synthesized":"O my dove in the clefts of the rock, in the crevices of the cliff, let me see your face, let me hear your voice; for your voice is sweet, and your countenance is lovely.","sources":{"KJV":{"text":"O my dove, that art in the clefts of the rock, in the secret places of the stairs, let me see thy countenance, let me hear thy voice; for sweet is thy voice, and thy countenance is comely."},"BSB":{"text":"O my dove in the clefts of the rock, in the crevices of the cliff, let me see your face, let me hear your voice; for your voice is sweet, and your countenance is lovely."}},"definableWords":["see","hear","voice"],"peopleInVerse":[]},"15":{"text":"Take us the foxes, the little foxes, that spoil the vines: for our vines have tender grapes.","ref":"Song of Solomon 2:15","synthesized":"Catch for us the foxes— the little foxes that ruin the vineyards— for our vineyards are in bloom.","sources":{"KJV":{"text":"Take us the foxes, the little foxes, that spoil the vines: for our vines have tender grapes."},"BSB":{"text":"Catch for us the foxes— the little foxes that ruin the vineyards— for our vineyards are in bloom."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"My beloved is mine, and I am his: he feedeth among the lilies.","ref":"Song of Solomon 2:16","synthesized":"My beloved is mine and I am his; he pastures his flock among the lilies.","sources":{"KJV":{"text":"My beloved is mine, and I am his: he feedeth among the lilies."},"BSB":{"text":"My beloved is mine and I am his; he pastures his flock among the lilies."}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"Until the day break, and the shadows flee away, turn, my beloved, and be thou like a roe or a young hart upon the mountains of Bether.","ref":"Song of Solomon 2:17","synthesized":"Before the day breaks and shadows flee, turn, my beloved, and be like a gazelle or a young stag on the mountains of Bether.","sources":{"KJV":{"text":"Until the day break, and the shadows flee away, turn, my beloved, and be thou like a roe or a young hart upon the mountains of Bether."},"BSB":{"text":"Before the day breaks and shadows flee, turn, my beloved, and be like a gazelle or a young stag on the mountains of Bether."}},"definableWords":["day","or"],"peopleInVerse":[]}}},"3":{"chapter":"3","title":"I FOUND HIM WHOM MY SOUL LOVETH","verses":{"1":{"text":"By night on my bed I sought him whom my soul loveth: I sought him, but I found him not.","ref":"Song of Solomon 3:1","synthesized":"On my bed at night I sought the one I love; I sought him, but did not find him.","sources":{"KJV":{"text":"By night on my bed I sought him whom my soul loveth: I sought him, but I found him not."},"BSB":{"text":"On my bed at night I sought the one I love; I sought him, but did not find him."}},"definableWords":["night","one","love"],"peopleInVerse":[]},"2":{"text":"I will rise now, and go about the city in the streets, and in the broad ways I will seek him whom my soul loveth: I sought him, but I found him not.","ref":"Song of Solomon 3:2","synthesized":"I will arise now and go about the city, through the streets and squares. I will seek the one I love. So I sought him but did not find him.","sources":{"KJV":{"text":"I will rise now, and go about the city in the streets, and in the broad ways I will seek him whom my soul loveth: I sought him, but I found him not."},"BSB":{"text":"I will arise now and go about the city, through the streets and squares. I will seek the one I love. So I sought him but did not find him."}},"definableWords":["seek","one","love"],"peopleInVerse":[]},"3":{"text":"The watchmen that go about the city found me: to whom I said, Saw ye him whom my soul loveth?","ref":"Song of Solomon 3:3","synthesized":"I encountered the watchmen on their rounds of the city: “Have you seen the one I love?”","sources":{"KJV":{"text":"The watchmen that go about the city found me: to whom I said, Saw ye him whom my soul loveth?"},"BSB":{"text":"I encountered the watchmen on their rounds of the city: “Have you seen the one I love?”"}},"definableWords":["one","love"],"peopleInVerse":[]},"4":{"text":"It was but a little that I passed from them, but I found him whom my soul loveth: I held him, and would not let him go, until I had brought him into my mother’s house, and into the chamber of her that conceived me.","ref":"Song of Solomon 3:4","synthesized":"I had just passed them when I found the one I love. I held him and would not let go until I had brought him to my mother’s house, to the chamber of the one who conceived me.","sources":{"KJV":{"text":"It was but a little that I passed from them, but I found him whom my soul loveth: I held him, and would not let him go, until I had brought him into my mother’s house, and into the chamber of her that conceived me."},"BSB":{"text":"I had just passed them when I found the one I love. I held him and would not let go until I had brought him to my mother’s house, to the chamber of the one who conceived me."}},"definableWords":["one","love","mother","house"],"peopleInVerse":[]},"5":{"text":"I charge you, O ye daughters of Jerusalem, by the roes, and by the hinds of the field, that ye stir not up, nor awake my love, till he please.","ref":"Song of Solomon 3:5","synthesized":"O daughters of Jerusalem, I adjure you by the gazelles and does of the field: Do not arouse or awaken love until the time is right.","sources":{"KJV":{"text":"I charge you, O ye daughters of Jerusalem, by the roes, and by the hinds of the field, that ye stir not up, nor awake my love, till he please."},"BSB":{"text":"O daughters of Jerusalem, I adjure you by the gazelles and does of the field: Do not arouse or awaken love until the time is right."}},"definableWords":["daughters","Jerusalem","field","or","love"],"peopleInVerse":[]},"6":{"text":"Who is this that cometh out of the wilderness like pillars of smoke, perfumed with myrrh and frankincense, with all powders of the merchant?","ref":"Song of Solomon 3:6","synthesized":"Who is this coming up from the wilderness like a column of smoke, scented with myrrh and frankincense from all the spices of the merchant?","sources":{"KJV":{"text":"Who is this that cometh out of the wilderness like pillars of smoke, perfumed with myrrh and frankincense, with all powders of the merchant?"},"BSB":{"text":"Who is this coming up from the wilderness like a column of smoke, scented with myrrh and frankincense from all the spices of the merchant?"}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Behold his bed, which is Solomon’s; threescore valiant men are about it, of the valiant of Israel.","ref":"Song of Solomon 3:7","synthesized":"Behold, it is Solomon’s carriage, escorted by sixty of the mightiest men of Israel.","sources":{"KJV":{"text":"Behold his bed, which is Solomon’s; threescore valiant men are about it, of the valiant of Israel."},"BSB":{"text":"Behold, it is Solomon’s carriage, escorted by sixty of the mightiest men of Israel."}},"definableWords":["men","Israel"],"peopleInVerse":["Solomon"]},"8":{"text":"They all hold swords, being expert in war: every man hath his sword upon his thigh because of fear in the night.","ref":"Song of Solomon 3:8","synthesized":"All are skilled with the sword, experienced in warfare. Each has his sword at his side prepared for the terror of the night.","sources":{"KJV":{"text":"They all hold swords, being expert in war: every man hath his sword upon his thigh because of fear in the night."},"BSB":{"text":"All are skilled with the sword, experienced in warfare. Each has his sword at his side prepared for the terror of the night."}},"definableWords":["night"],"peopleInVerse":[]},"9":{"text":"King Solomon made himself a chariot of the wood of Lebanon.","ref":"Song of Solomon 3:9","synthesized":"King Solomon has made his carriage out of the timber of Lebanon.","sources":{"KJV":{"text":"King Solomon made himself a chariot of the wood of Lebanon."},"BSB":{"text":"King Solomon has made his carriage out of the timber of Lebanon."}},"definableWords":["King","made"],"peopleInVerse":["Solomon"]},"10":{"text":"He made the pillars thereof of silver, the bottom thereof of gold, the covering of it of purple, the midst thereof being paved with love, for the daughters of Jerusalem.","ref":"Song of Solomon 3:10","synthesized":"He has made its posts of silver, its base of gold, its seat of purple fabric. Its interior is inlaid with love by the daughters of Jerusalem.","sources":{"KJV":{"text":"He made the pillars thereof of silver, the bottom thereof of gold, the covering of it of purple, the midst thereof being paved with love, for the daughters of Jerusalem."},"BSB":{"text":"He has made its posts of silver, its base of gold, its seat of purple fabric. Its interior is inlaid with love by the daughters of Jerusalem."}},"definableWords":["made","love","daughters","Jerusalem"],"peopleInVerse":[]},"11":{"text":"Go forth, O ye daughters of Zion, and behold king Solomon with the crown wherewith his mother crowned him in the day of his espousals, and in the day of the gladness of his heart.","ref":"Song of Solomon 3:11","synthesized":"Come out, O daughters of Zion, and gaze at King Solomon, wearing the crown his mother bestowed on the day of his wedding— the day of his heart’s rejoicing.","sources":{"KJV":{"text":"Go forth, O ye daughters of Zion, and behold king Solomon with the crown wherewith his mother crowned him in the day of his espousals, and in the day of the gladness of his heart."},"BSB":{"text":"Come out, O daughters of Zion, and gaze at King Solomon, wearing the crown his mother bestowed on the day of his wedding— the day of his heart’s rejoicing."}},"definableWords":["daughters","Zion","King","crown","mother","day","heart"],"peopleInVerse":["Solomon"]}}},"4":{"chapter":"4","title":"THOU ART ALL FAIR, MY LOVE","verses":{"1":{"text":"Behold, thou art fair, my love; behold, thou art fair; thou hast doves’ eyes within thy locks: thy hair is as a flock of goats, that appear from mount Gilead.","ref":"Song of Solomon 4:1","synthesized":"How beautiful you are, my darling— how very beautiful! Your eyes are like doves behind your veil. Your hair is like a flock of goats streaming down Mount Gilead.","sources":{"KJV":{"text":"Behold, thou art fair, my love; behold, thou art fair; thou hast doves’ eyes within thy locks: thy hair is as a flock of goats, that appear from mount Gilead."},"BSB":{"text":"How beautiful you are, my darling— how very beautiful! Your eyes are like doves behind your veil. Your hair is like a flock of goats streaming down Mount Gilead."}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"Thy teeth are like a flock of sheep that are even shorn, which came up from the washing; whereof every one bear twins, and none is barren among them.","ref":"Song of Solomon 4:2","synthesized":"Your teeth are like a flock of newly shorn sheep coming up from the washing; each has its twin, and not one of them is lost.","sources":{"KJV":{"text":"Thy teeth are like a flock of sheep that are even shorn, which came up from the washing; whereof every one bear twins, and none is barren among them."},"BSB":{"text":"Your teeth are like a flock of newly shorn sheep coming up from the washing; each has its twin, and not one of them is lost."}},"definableWords":["one"],"peopleInVerse":[]},"3":{"text":"Thy lips are like a thread of scarlet, and thy speech is comely: thy temples are like a piece of a pomegranate within thy locks.","ref":"Song of Solomon 4:3","synthesized":"Your lips are like a scarlet ribbon, and your mouth is lovely. Your brow behind your veil is like a slice of pomegranate.","sources":{"KJV":{"text":"Thy lips are like a thread of scarlet, and thy speech is comely: thy temples are like a piece of a pomegranate within thy locks."},"BSB":{"text":"Your lips are like a scarlet ribbon, and your mouth is lovely. Your brow behind your veil is like a slice of pomegranate."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Thy neck is like the tower of David builded for an armoury, whereon there hang a thousand bucklers, all shields of mighty men.","ref":"Song of Solomon 4:4","synthesized":"Your neck is like the tower of David, built with rows of stones; on it hang a thousand shields, all of them shields of warriors.","sources":{"KJV":{"text":"Thy neck is like the tower of David builded for an armoury, whereon there hang a thousand bucklers, all shields of mighty men."},"BSB":{"text":"Your neck is like the tower of David, built with rows of stones; on it hang a thousand shields, all of them shields of warriors."}},"definableWords":[],"peopleInVerse":["David"]},"5":{"text":"Thy two breasts are like two young roes that are twins, which feed among the lilies.","ref":"Song of Solomon 4:5","synthesized":"Your breasts are like two fawns, twins of a gazelle grazing among the lilies.","sources":{"KJV":{"text":"Thy two breasts are like two young roes that are twins, which feed among the lilies."},"BSB":{"text":"Your breasts are like two fawns, twins of a gazelle grazing among the lilies."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"Until the day break, and the shadows flee away, I will get me to the mountain of myrrh, and to the hill of frankincense.","ref":"Song of Solomon 4:6","synthesized":"Before the day breaks and the shadows flee, I will make my way to the mountain of myrrh and to the hill of frankincense.","sources":{"KJV":{"text":"Until the day break, and the shadows flee away, I will get me to the mountain of myrrh, and to the hill of frankincense."},"BSB":{"text":"Before the day breaks and the shadows flee, I will make my way to the mountain of myrrh and to the hill of frankincense."}},"definableWords":["day","make","way"],"peopleInVerse":[]},"7":{"text":"Thou art all fair, my love; there is no spot in thee.","ref":"Song of Solomon 4:7","synthesized":"You are altogether beautiful, my darling; in you there is no flaw.","sources":{"KJV":{"text":"Thou art all fair, my love; there is no spot in thee."},"BSB":{"text":"You are altogether beautiful, my darling; in you there is no flaw."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"Come with me from Lebanon, my spouse, with me from Lebanon: look from the top of Amana, from the top of Shenir and Hermon, from the lions’ dens, from the mountains of the leopards.","ref":"Song of Solomon 4:8","synthesized":"Come with me from Lebanon, my bride, come with me from Lebanon! Descend from the peak of Amana, from the summits of Senir and Hermon, from the dens of the lions, from the mountains of the leopards.","sources":{"KJV":{"text":"Come with me from Lebanon, my spouse, with me from Lebanon: look from the top of Amana, from the top of Shenir and Hermon, from the lions’ dens, from the mountains of the leopards."},"BSB":{"text":"Come with me from Lebanon, my bride, come with me from Lebanon! Descend from the peak of Amana, from the summits of Senir and Hermon, from the dens of the lions, from the mountains of the leopards."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"Thou hast ravished my heart, my sister, my spouse; thou hast ravished my heart with one of thine eyes, with one chain of thy neck.","ref":"Song of Solomon 4:9","synthesized":"You have captured my heart, my sister, my bride; you have stolen my heart with one glance of your eyes, with one jewel of your neck.","sources":{"KJV":{"text":"Thou hast ravished my heart, my sister, my spouse; thou hast ravished my heart with one of thine eyes, with one chain of thy neck."},"BSB":{"text":"You have captured my heart, my sister, my bride; you have stolen my heart with one glance of your eyes, with one jewel of your neck."}},"definableWords":["heart","sister","one"],"peopleInVerse":[]},"10":{"text":"How fair is thy love, my sister, my spouse! how much better is thy love than wine! and the smell of thine ointments than all spices!","ref":"Song of Solomon 4:10","synthesized":"How delightful is your love, my sister, my bride! Your love is much better than wine, and the fragrance of your perfume than all spices.","sources":{"KJV":{"text":"How fair is thy love, my sister, my spouse! how much better is thy love than wine! and the smell of thine ointments than all spices!"},"BSB":{"text":"How delightful is your love, my sister, my bride! Your love is much better than wine, and the fragrance of your perfume than all spices."}},"definableWords":["love","sister"],"peopleInVerse":[]},"11":{"text":"Thy lips, O my spouse, drop as the honeycomb: honey and milk are under thy tongue; and the smell of thy garments is like the smell of Lebanon.","ref":"Song of Solomon 4:11","synthesized":"Your lips, my bride, drip sweetness like the honeycomb; honey and milk are under your tongue, and the fragrance of your garments is like the aroma of Lebanon.","sources":{"KJV":{"text":"Thy lips, O my spouse, drop as the honeycomb: honey and milk are under thy tongue; and the smell of thy garments is like the smell of Lebanon."},"BSB":{"text":"Your lips, my bride, drip sweetness like the honeycomb; honey and milk are under your tongue, and the fragrance of your garments is like the aroma of Lebanon."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"A garden inclosed is my sister, my spouse; a spring shut up, a fountain sealed.","ref":"Song of Solomon 4:12","synthesized":"My sister, my bride, you are a garden locked up, a spring enclosed, a fountain sealed.","sources":{"KJV":{"text":"A garden inclosed is my sister, my spouse; a spring shut up, a fountain sealed."},"BSB":{"text":"My sister, my bride, you are a garden locked up, a spring enclosed, a fountain sealed."}},"definableWords":["sister","garden"],"peopleInVerse":[]},"13":{"text":"Thy plants are an orchard of pomegranates, with pleasant fruits; camphire, with spikenard,","ref":"Song of Solomon 4:13","synthesized":"Your branches are an orchard of pomegranates with the choicest of fruits, with henna and nard,","sources":{"KJV":{"text":"Thy plants are an orchard of pomegranates, with pleasant fruits; camphire, with spikenard,"},"BSB":{"text":"Your branches are an orchard of pomegranates with the choicest of fruits, with henna and nard,"}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"Spikenard and saffron; calamus and cinnamon, with all trees of frankincense; myrrh and aloes, with all the chief spices:","ref":"Song of Solomon 4:14","synthesized":"with nard and saffron, with calamus and cinnamon, with every kind of frankincense tree, with myrrh and aloes, with all the finest spices.","sources":{"KJV":{"text":"Spikenard and saffron; calamus and cinnamon, with all trees of frankincense; myrrh and aloes, with all the chief spices:"},"BSB":{"text":"with nard and saffron, with calamus and cinnamon, with every kind of frankincense tree, with myrrh and aloes, with all the finest spices."}},"definableWords":["tree"],"peopleInVerse":[]},"15":{"text":"A fountain of gardens, a well of living waters, and streams from Lebanon.","ref":"Song of Solomon 4:15","synthesized":"You are a garden spring, a well of fresh water flowing down from Lebanon.","sources":{"KJV":{"text":"A fountain of gardens, a well of living waters, and streams from Lebanon."},"BSB":{"text":"You are a garden spring, a well of fresh water flowing down from Lebanon."}},"definableWords":["garden","water"],"peopleInVerse":[]},"16":{"text":"Awake, O north wind; and come, thou south; blow upon my garden, that the spices thereof may flow out. Let my beloved come into his garden, and eat his pleasant fruits.","ref":"Song of Solomon 4:16","synthesized":"Awake, O north wind, and come, O south wind. Breathe on my garden and spread the fragrance of its spices. Let my beloved come into his garden and taste its choicest fruits.","sources":{"KJV":{"text":"Awake, O north wind; and come, thou south; blow upon my garden, that the spices thereof may flow out. Let my beloved come into his garden, and eat his pleasant fruits."},"BSB":{"text":"Awake, O north wind, and come, O south wind. Breathe on my garden and spread the fragrance of its spices. Let my beloved come into his garden and taste its choicest fruits."}},"definableWords":["garden"],"peopleInVerse":[]}}},"5":{"chapter":"5","title":"I AM SICK OF LOVE","verses":{"1":{"text":"I am come into my garden, my sister, my spouse: I have gathered my myrrh with my spice; I have eaten my honeycomb with my honey; I have drunk my wine with my milk: eat, O friends; drink, yea, drink abundantly, O beloved.","ref":"Song of Solomon 5:1","synthesized":"I have come to my garden, my sister, my bride; I have gathered my myrrh with my spice. I have eaten my honeycomb with my honey; I have drunk my wine with my milk.    Eat, O friends, and drink; drink freely, O beloved.","sources":{"KJV":{"text":"I am come into my garden, my sister, my spouse: I have gathered my myrrh with my spice; I have eaten my honeycomb with my honey; I have drunk my wine with my milk: eat, O friends; drink, yea, drink abundantly, O beloved."},"BSB":{"text":"I have come to my garden, my sister, my bride; I have gathered my myrrh with my spice. I have eaten my honeycomb with my honey; I have drunk my wine with my milk.    Eat, O friends, and drink; drink freely, O beloved."}},"definableWords":["garden","sister"],"peopleInVerse":[]},"2":{"text":"I sleep, but my heart waketh: it is the voice of my beloved that knocketh, saying, Open to me, my sister, my love, my dove, my undefiled: for my head is filled with dew, and my locks with the drops of the night.","ref":"Song of Solomon 5:2","synthesized":"I sleep, but my heart is awake. A sound! My beloved is knocking: “Open to me, my sister, my darling, my dove, my flawless one. My head is drenched with dew, my hair with the dampness of the night.”","sources":{"KJV":{"text":"I sleep, but my heart waketh: it is the voice of my beloved that knocketh, saying, Open to me, my sister, my love, my dove, my undefiled: for my head is filled with dew, and my locks with the drops of the night."},"BSB":{"text":"I sleep, but my heart is awake. A sound! My beloved is knocking: “Open to me, my sister, my darling, my dove, my flawless one. My head is drenched with dew, my hair with the dampness of the night.”"}},"definableWords":["heart","sister","one","night"],"peopleInVerse":[]},"3":{"text":"I have put off my coat; how shall I put it on? I have washed my feet; how shall I defile them?","ref":"Song of Solomon 5:3","synthesized":"I have taken off my robe— must I put it back on? I have washed my feet— must I soil them again?","sources":{"KJV":{"text":"I have put off my coat; how shall I put it on? I have washed my feet; how shall I defile them?"},"BSB":{"text":"I have taken off my robe— must I put it back on? I have washed my feet— must I soil them again?"}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"My beloved put in his hand by the hole of the door, and my bowels were moved for him.","ref":"Song of Solomon 5:4","synthesized":"My beloved put his hand to the latch; my heart pounded for him.","sources":{"KJV":{"text":"My beloved put in his hand by the hole of the door, and my bowels were moved for him."},"BSB":{"text":"My beloved put his hand to the latch; my heart pounded for him."}},"definableWords":["heart"],"peopleInVerse":[]},"5":{"text":"I rose up to open to my beloved; and my hands dropped with myrrh, and my fingers with sweet smelling myrrh, upon the handles of the lock.","ref":"Song of Solomon 5:5","synthesized":"I rose up to open for my beloved. My hands dripped with myrrh, my fingers with flowing myrrh on the handles of the bolt.","sources":{"KJV":{"text":"I rose up to open to my beloved; and my hands dropped with myrrh, and my fingers with sweet smelling myrrh, upon the handles of the lock."},"BSB":{"text":"I rose up to open for my beloved. My hands dripped with myrrh, my fingers with flowing myrrh on the handles of the bolt."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"I opened to my beloved; but my beloved had withdrawn himself, and was gone: my soul failed when he spake: I sought him, but I could not find him; I called him, but he gave me no answer.","ref":"Song of Solomon 5:6","synthesized":"I opened for my beloved, but he had turned and gone. My heart sank at his departure. I sought him, but did not find him. I called, but he did not answer.","sources":{"KJV":{"text":"I opened to my beloved; but my beloved had withdrawn himself, and was gone: my soul failed when he spake: I sought him, but I could not find him; I called him, but he gave me no answer."},"BSB":{"text":"I opened for my beloved, but he had turned and gone. My heart sank at his departure. I sought him, but did not find him. I called, but he did not answer."}},"definableWords":["heart"],"peopleInVerse":[]},"7":{"text":"The watchmen that went about the city found me, they smote me, they wounded me; the keepers of the walls took away my veil from me.","ref":"Song of Solomon 5:7","synthesized":"I encountered the watchmen on their rounds of the city. They beat me and bruised me; they took away my cloak, those guardians of the walls.","sources":{"KJV":{"text":"The watchmen that went about the city found me, they smote me, they wounded me; the keepers of the walls took away my veil from me."},"BSB":{"text":"I encountered the watchmen on their rounds of the city. They beat me and bruised me; they took away my cloak, those guardians of the walls."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"I charge you, O daughters of Jerusalem, if ye find my beloved, that ye tell him, that I am sick of love.","ref":"Song of Solomon 5:8","synthesized":"O daughters of Jerusalem, I adjure you, if you find my beloved, tell him I am sick with love.","sources":{"KJV":{"text":"I charge you, O daughters of Jerusalem, if ye find my beloved, that ye tell him, that I am sick of love."},"BSB":{"text":"O daughters of Jerusalem, I adjure you, if you find my beloved, tell him I am sick with love."}},"definableWords":["daughters","Jerusalem","love"],"peopleInVerse":[]},"9":{"text":"What is thy beloved more than another beloved, O thou fairest among women? what is thy beloved more than another beloved, that thou dost so charge us?","ref":"Song of Solomon 5:9","synthesized":"How is your beloved better than others, O most beautiful among women? How is your beloved better than another, that you charge us so?","sources":{"KJV":{"text":"What is thy beloved more than another beloved, O thou fairest among women? what is thy beloved more than another beloved, that thou dost so charge us?"},"BSB":{"text":"How is your beloved better than others, O most beautiful among women? How is your beloved better than another, that you charge us so?"}},"definableWords":["women","charge"],"peopleInVerse":[]},"10":{"text":"My beloved is white and ruddy, the chiefest among ten thousand.","ref":"Song of Solomon 5:10","synthesized":"My beloved is dazzling and ruddy, outstanding among ten thousand.","sources":{"KJV":{"text":"My beloved is white and ruddy, the chiefest among ten thousand."},"BSB":{"text":"My beloved is dazzling and ruddy, outstanding among ten thousand."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"His head is as the most fine gold, his locks are bushy, and black as a raven.","ref":"Song of Solomon 5:11","synthesized":"His head is purest gold; his hair is wavy and black as a raven.","sources":{"KJV":{"text":"His head is as the most fine gold, his locks are bushy, and black as a raven."},"BSB":{"text":"His head is purest gold; his hair is wavy and black as a raven."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"His eyes are as the eyes of doves by the rivers of waters, washed with milk, and fitly set.","ref":"Song of Solomon 5:12","synthesized":"His eyes are like doves beside the streams of water, bathed in milk and mounted like jewels.","sources":{"KJV":{"text":"His eyes are as the eyes of doves by the rivers of waters, washed with milk, and fitly set."},"BSB":{"text":"His eyes are like doves beside the streams of water, bathed in milk and mounted like jewels."}},"definableWords":["water"],"peopleInVerse":[]},"13":{"text":"His cheeks are as a bed of spices, as sweet flowers: his lips like lilies, dropping sweet smelling myrrh.","ref":"Song of Solomon 5:13","synthesized":"His cheeks are like beds of spice, towers of perfume. His lips are like lilies, dripping with flowing myrrh.","sources":{"KJV":{"text":"His cheeks are as a bed of spices, as sweet flowers: his lips like lilies, dropping sweet smelling myrrh."},"BSB":{"text":"His cheeks are like beds of spice, towers of perfume. His lips are like lilies, dripping with flowing myrrh."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"His hands are as gold rings set with the beryl: his belly is as bright ivory overlaid with sapphires.","ref":"Song of Solomon 5:14","synthesized":"His arms are rods of gold set with beryl. His body is an ivory panel bedecked with sapphires.","sources":{"KJV":{"text":"His hands are as gold rings set with the beryl: his belly is as bright ivory overlaid with sapphires."},"BSB":{"text":"His arms are rods of gold set with beryl. His body is an ivory panel bedecked with sapphires."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"His legs are as pillars of marble, set upon sockets of fine gold: his countenance is as Lebanon, excellent as the cedars.","ref":"Song of Solomon 5:15","synthesized":"His legs are pillars of marble set on bases of pure gold. His appearance is like Lebanon, as majestic as the cedars.","sources":{"KJV":{"text":"His legs are as pillars of marble, set upon sockets of fine gold: his countenance is as Lebanon, excellent as the cedars."},"BSB":{"text":"His legs are pillars of marble set on bases of pure gold. His appearance is like Lebanon, as majestic as the cedars."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"His mouth is most sweet: yea, he is altogether lovely. This is my beloved, and this is my friend, O daughters of Jerusalem.","ref":"Song of Solomon 5:16","synthesized":"His mouth is most sweet; he is altogether lovely. This is my beloved, and this is my friend, O daughters of Jerusalem.","sources":{"KJV":{"text":"His mouth is most sweet: yea, he is altogether lovely. This is my beloved, and this is my friend, O daughters of Jerusalem."},"BSB":{"text":"His mouth is most sweet; he is altogether lovely. This is my beloved, and this is my friend, O daughters of Jerusalem."}},"definableWords":["daughters","Jerusalem"],"peopleInVerse":[]}}},"6":{"chapter":"6","title":"MY BELOVED IS GONE","verses":{"1":{"text":"Whither is thy beloved gone, O thou fairest among women? whither is thy beloved turned aside? that we may seek him with thee.","ref":"Song of Solomon 6:1","synthesized":"Where has your beloved gone, O most beautiful among women? Which way has he turned? We will seek him with you.","sources":{"KJV":{"text":"Whither is thy beloved gone, O thou fairest among women? whither is thy beloved turned aside? that we may seek him with thee."},"BSB":{"text":"Where has your beloved gone, O most beautiful among women? Which way has he turned? We will seek him with you."}},"definableWords":["women","way","seek"],"peopleInVerse":[]},"2":{"text":"My beloved is gone down into his garden, to the beds of spices, to feed in the gardens, and to gather lilies.","ref":"Song of Solomon 6:2","synthesized":"My beloved has gone down to his garden, to the beds of spices, to pasture his flock in the gardens and to gather lilies.","sources":{"KJV":{"text":"My beloved is gone down into his garden, to the beds of spices, to feed in the gardens, and to gather lilies."},"BSB":{"text":"My beloved has gone down to his garden, to the beds of spices, to pasture his flock in the gardens and to gather lilies."}},"definableWords":["garden"],"peopleInVerse":[]},"3":{"text":"I am my beloved’s, and my beloved is mine: he feedeth among the lilies.","ref":"Song of Solomon 6:3","synthesized":"I belong to my beloved and he belongs to me; he pastures his flock among the lilies.","sources":{"KJV":{"text":"I am my beloved’s, and my beloved is mine: he feedeth among the lilies."},"BSB":{"text":"I belong to my beloved and he belongs to me; he pastures his flock among the lilies."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Thou art beautiful, O my love, as Tirzah, comely as Jerusalem, terrible as an army with banners.","ref":"Song of Solomon 6:4","synthesized":"You are as beautiful, my darling, as Tirzah, as lovely as Jerusalem, as majestic as troops with banners.","sources":{"KJV":{"text":"Thou art beautiful, O my love, as Tirzah, comely as Jerusalem, terrible as an army with banners."},"BSB":{"text":"You are as beautiful, my darling, as Tirzah, as lovely as Jerusalem, as majestic as troops with banners."}},"definableWords":["Jerusalem"],"peopleInVerse":[]},"5":{"text":"Turn away thine eyes from me, for they have overcome me: thy hair is as a flock of goats that appear from Gilead.","ref":"Song of Solomon 6:5","synthesized":"Turn your eyes away from me, for they have overcome me. Your hair is like a flock of goats streaming down from Gilead.","sources":{"KJV":{"text":"Turn away thine eyes from me, for they have overcome me: thy hair is as a flock of goats that appear from Gilead."},"BSB":{"text":"Turn your eyes away from me, for they have overcome me. Your hair is like a flock of goats streaming down from Gilead."}},"definableWords":["overcome"],"peopleInVerse":[]},"6":{"text":"Thy teeth are as a flock of sheep which go up from the washing, whereof every one beareth twins, and there is not one barren among them.","ref":"Song of Solomon 6:6","synthesized":"Your teeth are like a flock of sheep coming up from the washing; each has its twin, and not one of them is lost.","sources":{"KJV":{"text":"Thy teeth are as a flock of sheep which go up from the washing, whereof every one beareth twins, and there is not one barren among them."},"BSB":{"text":"Your teeth are like a flock of sheep coming up from the washing; each has its twin, and not one of them is lost."}},"definableWords":["one"],"peopleInVerse":[]},"7":{"text":"As a piece of a pomegranate are thy temples within thy locks.","ref":"Song of Solomon 6:7","synthesized":"Your brow behind your veil is like a slice of pomegranate.","sources":{"KJV":{"text":"As a piece of a pomegranate are thy temples within thy locks."},"BSB":{"text":"Your brow behind your veil is like a slice of pomegranate."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"There are threescore queens, and fourscore concubines, and virgins without number.","ref":"Song of Solomon 6:8","synthesized":"There are sixty queens and eighty concubines, and maidens without number,","sources":{"KJV":{"text":"There are threescore queens, and fourscore concubines, and virgins without number."},"BSB":{"text":"There are sixty queens and eighty concubines, and maidens without number,"}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"My dove, my undefiled is but one; she is the only one of her mother, she is the choice one of her that bare her. The daughters saw her, and blessed her; yea, the queens and the concubines, and they praised her.","ref":"Song of Solomon 6:9","synthesized":"but my dove, my perfect one, is unique, the favorite of the mother who bore her. The maidens see her and call her blessed; the queens and concubines sing her praises.","sources":{"KJV":{"text":"My dove, my undefiled is but one; she is the only one of her mother, she is the choice one of her that bare her. The daughters saw her, and blessed her; yea, the queens and the concubines, and they praised her."},"BSB":{"text":"but my dove, my perfect one, is unique, the favorite of the mother who bore her. The maidens see her and call her blessed; the queens and concubines sing her praises."}},"definableWords":["one","mother","see","blessed"],"peopleInVerse":[]},"10":{"text":"Who is she that looketh forth as the morning, fair as the moon, clear as the sun, and terrible as an army with banners?","ref":"Song of Solomon 6:10","synthesized":"Who is this who shines like the dawn, as fair as the moon, as bright as the sun, as majestic as the stars in procession?","sources":{"KJV":{"text":"Who is she that looketh forth as the morning, fair as the moon, clear as the sun, and terrible as an army with banners?"},"BSB":{"text":"Who is this who shines like the dawn, as fair as the moon, as bright as the sun, as majestic as the stars in procession?"}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"I went down into the garden of nuts to see the fruits of the valley, and to see whether the vine flourished, and the pomegranates budded.","ref":"Song of Solomon 6:11","synthesized":"I went down to the walnut grove to see the blossoms of the valley, to see if the vines were budding or the pomegranates were in bloom.","sources":{"KJV":{"text":"I went down into the garden of nuts to see the fruits of the valley, and to see whether the vine flourished, and the pomegranates budded."},"BSB":{"text":"I went down to the walnut grove to see the blossoms of the valley, to see if the vines were budding or the pomegranates were in bloom."}},"definableWords":["see","or"],"peopleInVerse":[]},"12":{"text":"Or ever I was aware, my soul made me like the chariots of Amminadib.","ref":"Song of Solomon 6:12","synthesized":"Before I realized it, my desire had set me among the royal chariots of my people.","sources":{"KJV":{"text":"Or ever I was aware, my soul made me like the chariots of Amminadib."},"BSB":{"text":"Before I realized it, my desire had set me among the royal chariots of my people."}},"definableWords":["people"],"peopleInVerse":[]},"13":{"text":"Return, return, O Shulamite; return, return, that we may look upon thee. What will ye see in the Shulamite? As it were the company of two armies.","ref":"Song of Solomon 6:13","synthesized":"Come back, come back, O Shulammite! Come back, come back, that we may gaze upon you.    Why do you look at the Shulammite, as on the dance of Mahanaim?","sources":{"KJV":{"text":"Return, return, O Shulamite; return, return, that we may look upon thee. What will ye see in the Shulamite? As it were the company of two armies."},"BSB":{"text":"Come back, come back, O Shulammite! Come back, come back, that we may gaze upon you.    Why do you look at the Shulammite, as on the dance of Mahanaim?"}},"definableWords":[],"peopleInVerse":[]}}},"7":{"chapter":"7","title":"HOW BEAUTIFUL ARE THY FEET","verses":{"1":{"text":"How beautiful are thy feet with shoes, O prince’s daughter! the joints of thy thighs are like jewels, the work of the hands of a cunning workman.","ref":"Song of Solomon 7:1","synthesized":"How beautiful are your sandaled feet, O daughter of the prince! The curves of your thighs are like jewels, the handiwork of a master.","sources":{"KJV":{"text":"How beautiful are thy feet with shoes, O prince’s daughter! the joints of thy thighs are like jewels, the work of the hands of a cunning workman."},"BSB":{"text":"How beautiful are your sandaled feet, O daughter of the prince! The curves of your thighs are like jewels, the handiwork of a master."}},"definableWords":["daughter","prince"],"peopleInVerse":[]},"2":{"text":"Thy navel is like a round goblet, which wanteth not liquor: thy belly is like an heap of wheat set about with lilies.","ref":"Song of Solomon 7:2","synthesized":"Your navel is a rounded goblet; it never lacks blended wine. Your waist is a mound of wheat encircled by the lilies.","sources":{"KJV":{"text":"Thy navel is like a round goblet, which wanteth not liquor: thy belly is like an heap of wheat set about with lilies."},"BSB":{"text":"Your navel is a rounded goblet; it never lacks blended wine. Your waist is a mound of wheat encircled by the lilies."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"Thy two breasts are like two young roes that are twins.","ref":"Song of Solomon 7:3","synthesized":"Your breasts are like two fawns, twins of a gazelle.","sources":{"KJV":{"text":"Thy two breasts are like two young roes that are twins."},"BSB":{"text":"Your breasts are like two fawns, twins of a gazelle."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Thy neck is as a tower of ivory; thine eyes like the fishpools in Heshbon, by the gate of Bathrabbim: thy nose is as the tower of Lebanon which looketh toward Damascus.","ref":"Song of Solomon 7:4","synthesized":"Your neck is like a tower made of ivory; your eyes are like the pools of Heshbon by the gate of Bath-rabbim; your nose is like the tower of Lebanon, facing toward Damascus.","sources":{"KJV":{"text":"Thy neck is as a tower of ivory; thine eyes like the fishpools in Heshbon, by the gate of Bathrabbim: thy nose is as the tower of Lebanon which looketh toward Damascus."},"BSB":{"text":"Your neck is like a tower made of ivory; your eyes are like the pools of Heshbon by the gate of Bath-rabbim; your nose is like the tower of Lebanon, facing toward Damascus."}},"definableWords":["made"],"peopleInVerse":[]},"5":{"text":"Thine head upon thee is like Carmel, and the hair of thine head like purple; the king is held in the galleries.","ref":"Song of Solomon 7:5","synthesized":"Your head crowns you like Mount Carmel, the hair of your head like purple threads; the king is captured in your tresses.","sources":{"KJV":{"text":"Thine head upon thee is like Carmel, and the hair of thine head like purple; the king is held in the galleries."},"BSB":{"text":"Your head crowns you like Mount Carmel, the hair of your head like purple threads; the king is captured in your tresses."}},"definableWords":["king"],"peopleInVerse":[]},"6":{"text":"How fair and how pleasant art thou, O love, for delights!","ref":"Song of Solomon 7:6","synthesized":"How fair and pleasant you are, O love, with your delights!","sources":{"KJV":{"text":"How fair and how pleasant art thou, O love, for delights!"},"BSB":{"text":"How fair and pleasant you are, O love, with your delights!"}},"definableWords":["love"],"peopleInVerse":[]},"7":{"text":"This thy stature is like to a palm tree, and thy breasts to clusters of grapes.","ref":"Song of Solomon 7:7","synthesized":"Your stature is like a palm tree; your breasts are clusters of fruit.","sources":{"KJV":{"text":"This thy stature is like to a palm tree, and thy breasts to clusters of grapes."},"BSB":{"text":"Your stature is like a palm tree; your breasts are clusters of fruit."}},"definableWords":["tree"],"peopleInVerse":[]},"8":{"text":"I said, I will go up to the palm tree, I will take hold of the boughs thereof: now also thy breasts shall be as clusters of the vine, and the smell of thy nose like apples;","ref":"Song of Solomon 7:8","synthesized":"I said, “I will climb the palm tree; I will take hold of its fruit.” May your breasts be like clusters of the vine, the fragrance of your breath like apples,","sources":{"KJV":{"text":"I said, I will go up to the palm tree, I will take hold of the boughs thereof: now also thy breasts shall be as clusters of the vine, and the smell of thy nose like apples;"},"BSB":{"text":"I said, “I will climb the palm tree; I will take hold of its fruit.” May your breasts be like clusters of the vine, the fragrance of your breath like apples,"}},"definableWords":["tree","breath"],"peopleInVerse":[]},"9":{"text":"And the roof of thy mouth like the best wine for my beloved, that goeth down sweetly, causing the lips of those that are asleep to speak.","ref":"Song of Solomon 7:9","synthesized":"and your mouth like the finest wine.    May it flow smoothly to my beloved, gliding gently over lips and teeth.","sources":{"KJV":{"text":"And the roof of thy mouth like the best wine for my beloved, that goeth down sweetly, causing the lips of those that are asleep to speak."},"BSB":{"text":"and your mouth like the finest wine.    May it flow smoothly to my beloved, gliding gently over lips and teeth."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"I am my beloved’s, and his desire is toward me.","ref":"Song of Solomon 7:10","synthesized":"I belong to my beloved, and his desire is for me.","sources":{"KJV":{"text":"I am my beloved’s, and his desire is toward me."},"BSB":{"text":"I belong to my beloved, and his desire is for me."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"Come, my beloved, let us go forth into the field; let us lodge in the villages.","ref":"Song of Solomon 7:11","synthesized":"Come, my beloved, let us go to the countryside; let us spend the night among the wildflowers.","sources":{"KJV":{"text":"Come, my beloved, let us go forth into the field; let us lodge in the villages."},"BSB":{"text":"Come, my beloved, let us go to the countryside; let us spend the night among the wildflowers."}},"definableWords":["night"],"peopleInVerse":[]},"12":{"text":"Let us get up early to the vineyards; let us see if the vine flourish, whether the tender grape appear, and the pomegranates bud forth: there will I give thee my loves.","ref":"Song of Solomon 7:12","synthesized":"Let us go early to the vineyards to see if the vine has budded, if the blossom has opened, if the pomegranates are in bloom— there I will give you my love.","sources":{"KJV":{"text":"Let us get up early to the vineyards; let us see if the vine flourish, whether the tender grape appear, and the pomegranates bud forth: there will I give thee my loves."},"BSB":{"text":"Let us go early to the vineyards to see if the vine has budded, if the blossom has opened, if the pomegranates are in bloom— there I will give you my love."}},"definableWords":["see","love"],"peopleInVerse":[]},"13":{"text":"The mandrakes give a smell, and at our gates are all manner of pleasant fruits, new and old, which I have laid up for thee, O my beloved.","ref":"Song of Solomon 7:13","synthesized":"The mandrakes send forth a fragrance, and at our door is every delicacy, new as well as old, that I have treasured up for you, my beloved.","sources":{"KJV":{"text":"The mandrakes give a smell, and at our gates are all manner of pleasant fruits, new and old, which I have laid up for thee, O my beloved."},"BSB":{"text":"The mandrakes send forth a fragrance, and at our door is every delicacy, new as well as old, that I have treasured up for you, my beloved."}},"definableWords":[],"peopleInVerse":[]}}},"8":{"chapter":"8","title":"LOVE IS STRONG AS DEATH","verses":{"1":{"text":"O that thou wert as my brother, that sucked the breasts of my mother! when I should find thee without, I would kiss thee; yea, I should not be despised.","ref":"Song of Solomon 8:1","synthesized":"O that you were to me like a brother who nursed at my mother’s breasts! If I found you outdoors, I would kiss you, and no one would despise me.","sources":{"KJV":{"text":"O that thou wert as my brother, that sucked the breasts of my mother! when I should find thee without, I would kiss thee; yea, I should not be despised."},"BSB":{"text":"O that you were to me like a brother who nursed at my mother’s breasts! If I found you outdoors, I would kiss you, and no one would despise me."}},"definableWords":["brother","mother","one"],"peopleInVerse":[]},"2":{"text":"I would lead thee, and bring thee into my mother’s house, who would instruct me: I would cause thee to drink of spiced wine of the juice of my pomegranate.","ref":"Song of Solomon 8:2","synthesized":"I would lead you and bring you to the house of my mother who taught me. I would give you spiced wine to drink, the nectar of my pomegranates.","sources":{"KJV":{"text":"I would lead thee, and bring thee into my mother’s house, who would instruct me: I would cause thee to drink of spiced wine of the juice of my pomegranate."},"BSB":{"text":"I would lead you and bring you to the house of my mother who taught me. I would give you spiced wine to drink, the nectar of my pomegranates."}},"definableWords":["house","mother"],"peopleInVerse":[]},"3":{"text":"His left hand should be under my head, and his right hand should embrace me.","ref":"Song of Solomon 8:3","synthesized":"His left hand is under my head, and his right arm embraces me.","sources":{"KJV":{"text":"His left hand should be under my head, and his right hand should embrace me."},"BSB":{"text":"His left hand is under my head, and his right arm embraces me."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"I charge you, O daughters of Jerusalem, that ye stir not up, nor awake my love, until he please.","ref":"Song of Solomon 8:4","synthesized":"O daughters of Jerusalem, I adjure you: Do not arouse or awaken love until the time is right.","sources":{"KJV":{"text":"I charge you, O daughters of Jerusalem, that ye stir not up, nor awake my love, until he please."},"BSB":{"text":"O daughters of Jerusalem, I adjure you: Do not arouse or awaken love until the time is right."}},"definableWords":["daughters","Jerusalem","or","love"],"peopleInVerse":[]},"5":{"text":"Who is this that cometh up from the wilderness, leaning upon her beloved? I raised thee up under the apple tree: there thy mother brought thee forth: there she brought thee forth that bare thee.","ref":"Song of Solomon 8:5","synthesized":"Who is this coming up from the wilderness, leaning on her beloved?    I roused you under the apple tree; there your mother conceived you; there she travailed and brought you forth.","sources":{"KJV":{"text":"Who is this that cometh up from the wilderness, leaning upon her beloved? I raised thee up under the apple tree: there thy mother brought thee forth: there she brought thee forth that bare thee."},"BSB":{"text":"Who is this coming up from the wilderness, leaning on her beloved?    I roused you under the apple tree; there your mother conceived you; there she travailed and brought you forth."}},"definableWords":["tree","mother"],"peopleInVerse":[]},"6":{"text":"Set me as a seal upon thine heart, as a seal upon thine arm: for love is strong as death; jealousy is cruel as the grave: the coals thereof are coals of fire, which hath a most vehement flame.","ref":"Song of Solomon 8:6","synthesized":"Set me as a seal over your heart, as a seal upon your arm. For love is as strong as death, its jealousy as unrelenting as Sheol. Its sparks are fiery flames, the fiercest blaze of all.","sources":{"KJV":{"text":"Set me as a seal upon thine heart, as a seal upon thine arm: for love is strong as death; jealousy is cruel as the grave: the coals thereof are coals of fire, which hath a most vehement flame."},"BSB":{"text":"Set me as a seal over your heart, as a seal upon your arm. For love is as strong as death, its jealousy as unrelenting as Sheol. Its sparks are fiery flames, the fiercest blaze of all."}},"definableWords":["heart","love","strong","death"],"peopleInVerse":[]},"7":{"text":"Many waters cannot quench love, neither can the floods drown it: if a man would give all the substance of his house for love, it would utterly be contemned.","ref":"Song of Solomon 8:7","synthesized":"Mighty waters cannot quench love; rivers cannot sweep it away. If a man were to give all the wealth of his house for love, his offer would be utterly scorned.","sources":{"KJV":{"text":"Many waters cannot quench love, neither can the floods drown it: if a man would give all the substance of his house for love, it would utterly be contemned."},"BSB":{"text":"Mighty waters cannot quench love; rivers cannot sweep it away. If a man were to give all the wealth of his house for love, his offer would be utterly scorned."}},"definableWords":["mighty","waters","love","man","house"],"peopleInVerse":[]},"8":{"text":"We have a little sister, and she hath no breasts: what shall we do for our sister in the day when she shall be spoken for?","ref":"Song of Solomon 8:8","synthesized":"We have a little sister, and her breasts are not yet grown. What shall we do for our sister on the day she is spoken for?","sources":{"KJV":{"text":"We have a little sister, and she hath no breasts: what shall we do for our sister in the day when she shall be spoken for?"},"BSB":{"text":"We have a little sister, and her breasts are not yet grown. What shall we do for our sister on the day she is spoken for?"}},"definableWords":["sister","day"],"peopleInVerse":[]},"9":{"text":"If she be a wall, we will build upon her a palace of silver: and if she be a door, we will inclose her with boards of cedar.","ref":"Song of Solomon 8:9","synthesized":"If she is a wall, we will build a tower of silver upon her. If she is a door, we will enclose her with panels of cedar.","sources":{"KJV":{"text":"If she be a wall, we will build upon her a palace of silver: and if she be a door, we will inclose her with boards of cedar."},"BSB":{"text":"If she is a wall, we will build a tower of silver upon her. If she is a door, we will enclose her with panels of cedar."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"I am a wall, and my breasts like towers: then was I in his eyes as one that found favour.","ref":"Song of Solomon 8:10","synthesized":"I am a wall, and my breasts are like towers. So I have become in his eyes like one who brings peace.","sources":{"KJV":{"text":"I am a wall, and my breasts like towers: then was I in his eyes as one that found favour."},"BSB":{"text":"I am a wall, and my breasts are like towers. So I have become in his eyes like one who brings peace."}},"definableWords":["one","peace"],"peopleInVerse":[]},"11":{"text":"Solomon had a vineyard at Baalhamon; he let out the vineyard unto keepers; every one for the fruit thereof was to bring a thousand pieces of silver.","ref":"Song of Solomon 8:11","synthesized":"Solomon had a vineyard in Baal-hamon. He leased it to the tenants. For its fruit, each was to bring a thousand shekels of silver.","sources":{"KJV":{"text":"Solomon had a vineyard at Baalhamon; he let out the vineyard unto keepers; every one for the fruit thereof was to bring a thousand pieces of silver."},"BSB":{"text":"Solomon had a vineyard in Baal-hamon. He leased it to the tenants. For its fruit, each was to bring a thousand shekels of silver."}},"definableWords":[],"peopleInVerse":["Solomon"]},"12":{"text":"My vineyard, which is mine, is before me: thou, O Solomon, must have a thousand, and those that keep the fruit thereof two hundred.","ref":"Song of Solomon 8:12","synthesized":"But my own vineyard is mine to give; the thousand shekels are for you, O Solomon, and two hundred are for those who tend its fruit.","sources":{"KJV":{"text":"My vineyard, which is mine, is before me: thou, O Solomon, must have a thousand, and those that keep the fruit thereof two hundred."},"BSB":{"text":"But my own vineyard is mine to give; the thousand shekels are for you, O Solomon, and two hundred are for those who tend its fruit."}},"definableWords":[],"peopleInVerse":["Solomon"]},"13":{"text":"Thou that dwellest in the gardens, the companions hearken to thy voice: cause me to hear it.","ref":"Song of Solomon 8:13","synthesized":"You who dwell in the gardens, my companions are listening for your voice. Let me hear it!","sources":{"KJV":{"text":"Thou that dwellest in the gardens, the companions hearken to thy voice: cause me to hear it."},"BSB":{"text":"You who dwell in the gardens, my companions are listening for your voice. Let me hear it!"}},"definableWords":["voice","hear"],"peopleInVerse":[]},"14":{"text":"Make haste, my beloved, and be thou like to a roe or to a young hart upon the mountains of spices.","ref":"Song of Solomon 8:14","synthesized":"Come away, my beloved, and be like a gazelle or a young stag on the mountains of spices.","sources":{"KJV":{"text":"Make haste, my beloved, and be thou like to a roe or to a young hart upon the mountains of spices."},"BSB":{"text":"Come away, my beloved, and be like a gazelle or a young stag on the mountains of spices."}},"definableWords":["or"],"peopleInVerse":[]}}}};